app.post('/search/msearch', async (req, res) => {
  try {
    const schema = Joi.object({
      searches: Joi.array().items(
        Joi.object({
          index: Joi.string().required(),
          query: Joi.object().required(),
          from: Joi.number().integer().min(0).default(0),
          size: Joi.number().integer().min(0).max(10000).default(10),
          source: Joi.alternatives().try(
            Joi.boolean(),
            Joi.array().items(Joi.string())
          )
        })
      ).required()
    });

    const { error, value } = schema.validate(req.body);
    
    if (error) {
      return res.status(400).json({
        error: 'Validation error',
        details: error.details.map(d => d.message)
      });
    }

    const body = value.searches.flatMap(search => [
      { index: search.index },
      {
        query: search.query,
        from: search.from,
        size: search.size,
        _source: search.source
      }
    ]);

    const result = await esClient.msearch({
      body: body
    });

    res.json({
      responses: result.responses.map(r => ({
        took: r.took,
        timed_out: r.timed_out,
        total: r.hits?.total,
        max_score: r.hits?.max_score,
        hits: r.hits?.hits,
        error: r.error
      }))
    });

  } catch (err) {
    console.error('Multi-search error:', err);
    res.status(500).json({
      error: 'Multi-search failed',
      message: err.message
    });
  }
});

