app.post('/validate-script', async (req, res) => {
  try {
    const schema = Joi.object({
      script: Joi.object({
        source: Joi.string().required(),
        params: Joi.object().default({}),
        lang: Joi.string().valid('painless', 'expression').default('painless')
      }).required()
    });

    const { error, value } = schema.validate(req.body);
    
    if (error) {
      return res.status(400).json({
        error: 'Validation error',
        details: error.details.map(d => d.message)
      });
    }

    res.json({
      valid: true,
      script: value.script
    });

  } catch (err) {
    res.status(500).json({
      valid: false,
      error: err.message
    });
  }
});

